parameters.jsCode:
const customers = $('Fetch New Customers').all().map(i => i.json);
const sentHistory = $('Fetch Sent History').all().map(i => i.json);

// Build dedup set
const alreadySent = new Set();
for (const s of sentHistory) {
  if (s.contact_email && s.email_type) {
    alreadySent.add(s.contact_email + '|' + s.email_type);
  }
}

const results = [];
const month = new Date().getMonth() + 1;
const seasonal = month >= 3 && month <= 5 ? 'spring cleanup and aeration' : month >= 6 && month <= 8 ? 'summer lawn care and fertilization' : month >= 9 && month <= 11 ? 'fall cleanup and gutter cleaning' : 'snow removal and winter prep';

for (const c of customers) {
  if (!c.email) continue;
  const daysSince = Math.floor((Date.now() - new Date(c.first_job_completed_at)) / (1000*60*60*24));
  let emailNum = null, subject = '', body = '';
  if (daysSince <= 1) { emailNum = 1; subject = 'Welcome to TotalGuard Yard Care, ' + c.first_name + '!'; body = 'Hi ' + c.first_name + ',\n\nWelcome to TotalGuard Yard Care! We\'re thrilled to have you as a customer. Your dedicated crew will be the same team every visit \u2014 same crew, same day, every week.\n\nQuestions? Call us at (608) 535-6057 or reply to this email.\n\n- The TotalGuard Team'; }
  else if (daysSince === 7) { emailNum = 2; subject = 'Lawn care tips from your TG crew'; body = 'Hi ' + c.first_name + ',\n\nA week in! Here are some quick tips to keep your yard looking great between visits...\n\nFor ' + (c.last_service || 'lawn care') + ': water deeply 2-3x per week, avoid cutting more than 1/3 of grass height at once.\n\n- The TotalGuard Team'; }
  else if (daysSince === 14) { emailNum = 3; subject = 'How are we doing, ' + c.first_name + '?'; body = 'Hi ' + c.first_name + ',\n\nWe hope you\'re loving your yard! If we\'ve exceeded your expectations, a quick Google review means the world to us:\n\nhttps://g.page/r/REVIEW_LINK\n\nIt only takes 30 seconds and helps us serve more Madison neighbors like you.\n\n- The TotalGuard Team'; }
  else if (daysSince === 21) { emailNum = 4; subject = 'Get $25 off \u2014 refer a neighbor!'; body = 'Hi ' + c.first_name + ',\n\nLove your yard? Share the love! Refer a neighbor to TotalGuard and you BOTH get $25 off your next service.\n\nJust have them mention your name when they book at tgyardcare.com.\n\n- The TotalGuard Team'; }
  else if (daysSince === 30) { emailNum = 5; subject = 'Your next TotalGuard service'; body = 'Hi ' + c.first_name + ',\n\nNow that you\'re settled in, have you considered our ' + seasonal + ' services? Book online at tgyardcare.com or call (608) 535-6057.\n\n- The TotalGuard Team'; }
  if (!emailNum) continue;

  const emailType = 'welcome_series_' + emailNum;
  if (alreadySent.has(c.email + '|' + emailType)) continue;

  results.push({ json: { ...c, emailNum, subject, body, daysSince, emailType } });
}
return results;

